sp_instance.widget_parameters:
{
	"html": {
		"value": "<div class="quick-actions-section">
<div class="section-title">Quick Actions</div>
<div class="section-sub">Your most important tasks, one click away</div>
<div class="cards-grid"><!-- My Requests --><a class="card" href="/pp?id=my_requests">
<div class="icon-circle"><span class="icon-emoji">📋</span></div>
<h3>My Requests</h3>
<p>Track your medicine orders and prescriptions</p>
<div class="btn-text">View My Requests &rarr;</div>
</a><!-- Report a Problem --><a class="card" href="/pp?id=sc_cat_item&amp;sys_id=f81a242d47d14f14516b5ac5316d43d7">
<div class="icon-circle"><span class="icon-emoji">⚠️</span></div>
<h3>Report a Problem</h3>
<p>Submit a complaint about your service or medicine</p>
<div class="btn-text">Report Now &rarr;</div>
</a><!-- Request Medicine --><a class="card" href="/pp?id=sc_cat_item&amp;sys_id=66570a20479d0714516b5ac5316d434d">
<div class="icon-circle"><span class="icon-emoji">💊</span></div>
<h3>Request Medicine</h3>
<p>Order new medicine or refill an existing prescription</p>
<div class="btn-text">Order Now &rarr;</div>
</a></div>
</div>
<style>
.quick-actions-section {
    margin: 48px 0;
    text-align: center;
}
.section-title {
    font-size: 28px;
    font-weight: 700;
    color: #0F172A;
    margin-bottom: 12px;
}
.section-sub {
    text-align: center;
    color: #64748B;
    margin-bottom: 40px;
    font-size: 15px;
}.cards-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 30px;
    justify-items: stretch;
    align-items: stretch;
    margin: 5px;
    padding: 0;
}

.card {
    background: #FFFFFF;
    border-radius: 28px;
    padding: 30px 20px 25px;
    text-align: center;
    border: 1px solid #E2E8F0;
    transition: all 0.25s ease;
    cursor: pointer;
    text-decoration: none;
    color: inherit;
    display: flex;
    flex-direction: column;
    /* إزالة min-width و max-width الثابتة */
    min-width: 0; /* يسمح للعنصر بالتقليص إذا لزم الأمر */
    width: 100%;
    box-sizing: border-box;
}

/* على الشاشات المتوسطة، إذا ضاقت المساحة جدا نرجع للـ flex-wrap */
@media (max-width: 800px) {
    .cards-grid {
        grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    }
}

@media (max-width: 600px) {
    .cards-grid {
        grid-template-columns: 1fr;
    }
}
.card:hover {
    transform: translateY(-6px);
    box-shadow: 0 20px 30px -12px rgba(0,0,0,0.1);
    border-color: #E60000;
}
.icon-circle {
    width: 80px;
    height: 80px;
    background: #FEF2F2;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 20px;
    transition: all 0.2s;
}
.card:hover .icon-circle {
    background: #E60000;
}
.icon-circle i {
    font-size: 36px;
    color: #E60000;
    transition: color 0.2s;
}
.card:hover .icon-circle i {
    color: white;
}
.card h3 {
    font-size: 20px;
    font-weight: 700;
    margin-bottom: 10px;
    color: #0F172A;
}
.card p {
    font-size: 14px;
    color: #64748B;
    line-height: 1.4;
    margin-bottom: 20px;
}
.card .btn-text {
    font-size: 14px;
    font-weight: 600;
    color: #E60000;
    border-top: 1px solid #E2E8F0;
    padding-top: 14px;
    margin-top: 8px;
}
@media (max-width: 768px) {
    .cards-grid {
        gap: 20px;
    }
    .card {
        min-width: 160px;
        padding: 20px 15px;
    }
    .icon-circle {
        width: 60px;
        height: 60px;
    }
    .icon-circle i {
        font-size: 28px;
    }
    .card h3 {
        font-size: 18px;
    }
}
/* نفس CSS السابق، مع إضافة تنسيق للإيموجي */
.icon-emoji {
    font-size: 36px;
    line-height: 1;
    transition: filter 0.2s;
}
.card:hover .icon-emoji {
    filter: brightness(0) invert(1);
}
/* باقي الـ CSS كما هو (cards-grid, icon-circle, etc.) */
/* انسخ باقي الـ CSS من الحل الأول مع إبقاء نفس الأسماء */

.quick-actions-section {
    margin: 48px -20px !important; /* سالب عشان يتجاوز padding الحاوية */
    padding-left: 0 !important;
    padding-right: 0 !important;
}
/* اجعل القسم كامل العرض */
.quick-actions-section {
    width: 100% !important;
    margin-left: 10px!important;
    margin-right: 0 !important;
    padding-left: 0 !important;
    padding-right: 0 !important;
}

</style>",
